1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	export function nextGeneration(cells: Cell[]): Cell[] {
15	  const liveCells = new Set(cells.map(cellKey));
16	  const isAlive = (cell: Cell): boolean => liveCells.has(cellKey(cell));
17	
18	  const candidates = cells.flatMap((cell) => [cell, ...neighborsOf(cell)]);
19	  const uniqueCandidates = new Map(candidates.map((cell) => [cellKey(cell), cell]));
20	
21	  return [...uniqueCandidates.values()].filter((cell) => {
22	    const liveNeighbors = neighborsOf(cell).filter(isAlive).length;
23	    return liveNeighbors === 3 || (liveNeighbors === 2 && isAlive(cell));
24	  });
25	}
